5. How to deal with missing values

# Convert haven-labelled vectors to plain vectors first
TEDS_clean &lt;- TEDS_2016 |&gt;
  mutate(across(where(haven::is.labelled), haven::zap_labels))

recode_missing_codes &lt;- function(x) {
  if (!is.numeric(x)) return(x)
  x |&gt;
    na_if(7) |&gt;
    na_if(8) |&gt;
    na_if(9) |&gt;
    na_if(97) |&gt;
    na_if(98) |&gt;
    na_if(99)
}

TEDS_clean &lt;- TEDS_clean |&gt;
  mutate(across(everything(), recode_missing_codes))


# Missing values in assignment variables
TEDS_clean |&gt;
  summarise(across(all_of(intersect(vars_needed, names(TEDS_clean))), ~ sum(is.na(.)))) |&gt;
  pivot_longer(everything(), names_to = "variable", values_to = "n_missing") |&gt;
  arrange(desc(n_missing))

# A tibble: 9 × 2
  variable   n_missing
  &lt;chr&gt;          &lt;int&gt;
1 votetsai         429
2 income           362
3 Tondu            121
4 edu               10
5 female             0
6 DPP                0
7 age                0
8 Taiwanese          0
9 Econ_worse         0


In this assignment, I handle missing values by putting known nonresponse codes to NA, then using drop_na() only on variables required by each specific model/table.
